   323→            </button>
   324→            <button
   325→              disabled={page >= totalPages}
   326→              onClick={() => setPage(page + 1)}
   327→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   328→              style={{
   329→                fontFamily: "var(--font-dm-sans)",
   330→                fontSize: "13px",
   331→                color: "#374151",
   332→                border: "1px solid #e8e8e5",
   333→              }}
   334→            >
   335→              Next
   336→            </button>
   337→          </div>
   338→        </div>
   339→      )}
   340→
   341→      {/* Delete confirmation */}
   342→      <ConfirmDialog
   343→        open={!!deletingId}
   344→        onOpenChange={(open) => {
   345→          if (!open) setDeletingId(null);
   346→        }}
   347→        title="Delete Semantic Release"
   348→        description="This will permanently delete this semantic release and its report."
   349→        onConfirm={async () => {
   350→          if (deletingId) {
   351→            await srApi.delete(deletingId);
   352→            mutateData();
   353→          }
   354→        }}
   355→      />
   356→    </div>
   357→  );
   358→}
