    39→func (m *mockSemanticReleasesStore) GetSemanticRelease(_ context.Context, id string) (*models.SemanticRelease, error) {
    40→	if m.getErr != nil {
    41→		return nil, m.getErr
    42→	}
    43→	for i := range m.releases {
    44→		if m.releases[i].ID == id {
    45→			return &m.releases[i], nil
    46→		}
    47→	}
    48→	return nil, fmt.Errorf("not found")
