    58→func (m *mockSemanticReleasesStore) DeleteSemanticRelease(_ context.Context, id string) error {
    59→	if m.deleteErr != nil {
    60→		return m.deleteErr
    61→	}
    62→	for i := range m.releases {
    63→		if m.releases[i].ID == id {
    64→			m.releases = append(m.releases[:i], m.releases[i+1:]...)
    65→			return nil
    66→		}
    67→	}
    68→	return fmt.Errorf("not found")
    69→}
