    14→interface ConfirmDialogProps {
    15→  open: boolean;
    16→  onOpenChange: (open: boolean) => void;
    17→  title: string;
    18→  description: string;
    19→  onConfirm: () => Promise<void>;
    20→  confirmLabel?: string;
    21→}
    22→
    23→export function ConfirmDialog({
    24→  open,
    25→  onOpenChange,
    26→  title,
    27→  description,
    28→  onConfirm,
    29→  confirmLabel = "Delete",
    30→}: ConfirmDialogProps) {
    31→  const [loading, setLoading] = useState(false);
    32→
    33→  const handleConfirm = async () => {
    34→    setLoading(true);
    35→    try {
    36→      await onConfirm();
    37→      onOpenChange(false);
    38→    } finally {
    39→      setLoading(false);
    40→    }
    41→  };
    42→
    43→  return (
    44→    <Dialog open={open} onOpenChange={onOpenChange}>
    45→      <DialogContent className="sm:max-w-md">
    46→        <DialogHeader>
    47→          <DialogTitle>{title}</DialogTitle>
    48→          <DialogDescription>{description}</DialogDescription>
    49→        </DialogHeader>
    50→        <DialogFooter>
    51→          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={loading}>
    52→            Cancel
    53→          </Button>
    54→          <Button variant="destructive" onClick={handleConfirm} disabled={loading}>
    55→            {loading ? "Deleting..." : confirmLabel}
    56→          </Button>
    57→        </DialogFooter>
    58→      </DialogContent>
    59→    </Dialog>
    60→  );
    61→}
